import ast
from typing import Any

def solve(condition: str, context: dict) -> bool:
    """Evaluate a Quorix condition string against a context dictionary.

    Args:
        condition: A condition like ``role == "manager" and level >= 3``.
        context: A dictionary mapping variable names to values.

    Returns:
        True if the condition holds, False otherwise.
    """
    try:
        tree = ast.parse(condition, mode="eval")
    except SyntaxError as exc:
        raise ValueError(f"Invalid condition syntax: {condition!r}") from exc

    def _eval_node(node: ast.AST) -> Any:
        """Recursively evaluate an AST node in the given context."""
        if isinstance(node, ast.Constant):
            # Python 3.8+ uses ast.Constant for literals
            return node.value
        elif isinstance(node, ast.Name):
            var_name = node.id
            if var_name in context:
                return context[var_name]
            # If not found, try built‑in constants (True, False, None)
            builtins = {"True": True, "False": False, "None": None}
            if var_name in builtins:
                return builtins[var_name]
            raise NameError(f"Undefined variable: {var_name!r}")
        elif isinstance(node, ast.UnaryOp):
            if isinstance(node.op, ast.Not):
                return not _eval_node(node.operand)
            # Other unary operators are not expected in conditions
            raise NotImplementedError(f"Unsupported unary operator: {type(node.op).__name__}")
        elif isinstance(node, ast.BoolOp):
            if isinstance(node.op, ast.And):
                result = True
                for val in node.values:
                    result = result and _eval_node(val)
                    # short‑circuit
                    if not result:
                        break
                return result
            elif isinstance(node.op, ast.Or):
                result = False
                for val in node.values:
                    result = result or _eval_node(val)
                    if result:
                        break
                return result
            else:
                raise NotImplementedError(f"Unsupported boolean operator: {type(node.op).__name__}")
        elif isinstance(node, ast.Compare):
            # Evaluate the left operand
            left_val = _eval_node(node.left)
            # Iterate over pairs of operators and comparators
            for op, comparator in zip(node.ops, node.comparators):
                right_val = _eval_node(comparator)
                if isinstance(op, ast.Eq):
                    if left_val != right_val:
                        return False
                elif isinstance(op, ast.NotEq):
                    if left_val == right_val:
                        return False
                elif isinstance(op, ast.Lt):
                    if not (left_val < right_val):
                        return False
                elif isinstance(op, ast.LtE):
                    if not (left_val <= right_val):
                        return False
                elif isinstance(op, ast.Gt):
                    if not (left_val > right_val):
                        return False
                elif isinstance(op, ast.GtE):
                    if not (left_val >= right_val):
                        return False
                elif isinstance(op, ast.In):
                    if left_val not in right_val:
                        return False
                elif isinstance(op, ast.NotIn):
                    if left_val in right_val:
                        return False
                elif isinstance(op, ast.Is):
                    if left_val is not right_val:
                        return False
                elif isinstance(op, ast.IsNot):
                    if left_val is right_val:
                        return False
                else:
                    raise NotImplementedError(f"Unsupported comparison operator: {type(op).__name__}")
                left_val = right_val  # for chained comparisons
            return True
        elif isinstance(node, ast.List):
            return [_eval_node(el) for el in node.elts]
        elif isinstance(node, ast.Tuple):
            return tuple(_eval_node(el) for el in node.elts)
        elif isinstance(node, ast.Dict):
            return {
                _eval_node(key): _eval_node(val)
                for key, val in zip(node.keys, node.values)
            }
        elif isinstance(node, ast.BinOp):
            # Binary operators (e.g., arithmetic) – not typical in conditions but handle a few
            left = _eval_node(node.left)
            right = _eval_node(node.right)
            if isinstance(node.op, ast.Add):
                return left + right
            elif isinstance(node.op, ast.Sub):
                return left - right
            elif isinstance(node.op, ast.Mult):
                return left * right
            elif isinstance(node.op, ast.Div):
                return left / right
            else:
                raise NotImplementedError(f"Unsupported binary operator: {type(node.op).__name__}")
        elif isinstance(node, ast.Attribute):
            # e.g., obj.attr – not required but keep safe
            obj = _eval_node(node.value)
            return getattr(obj, node.attr)
        else:
            raise NotImplementedError(f"Unsupported node type: {type(node).__name__}")

    result = _eval_node(tree.body)
    return bool(result)
