import ast
from typing import Any, Set


def _extract_roles(condition: str) -> Set[str]:
    """Extract role values from a policy condition string."""
    roles: Set[str] = set()
    try:
        tree = ast.parse(condition, mode="eval")
    except SyntaxError:
        return roles

    # Walk the AST to find comparisons like role == "value"
    for node in ast.walk(tree.body):
        if isinstance(node, ast.Compare):
            left = node.left
            if isinstance(left, ast.Name) and left.id == "role":
                for op, right in zip(node.ops, node.comparators):
                    if isinstance(op, (ast.Eq, ast.NotEq)):
                        if isinstance(right, ast.Constant) and isinstance(right.value, str):
                            roles.add(right.value)
                    # Also handle 'in' checks, e.g., role in ["admin", "user"]
                    elif isinstance(op, (ast.In, ast.NotIn)):
                        if isinstance(right, (ast.List, ast.Tuple)):
                            for elt in right.elts:
                                if isinstance(elt, ast.Constant) and isinstance(elt.value, str):
                                    roles.add(elt.value)
    return roles


